/* 代码来自墨千尾老师*/
/* 1. 重置所有 <input type="range"> 的默认浏览器样式 */
input[type="range"] {
    -webkit-appearance: none;
    appearance: none;
    width: 100%;
    background: transparent;
    cursor: pointer;
}
/* 2. 设计滑块的“轨道” (Track) */
input[type="range"]::-webkit-slider-runnable-track {
    width: 100%;
    height: 6px; /* 轨道的粗细 */
    /* 轨道的背景现在是一个静态的、完整的渐变色，✨︎渐变颜色自调下边两个数值，调整原理和上边那个一样 ✨︎ */
    background: linear-gradient(to right, #ebebeb, #b6ded7); 
    border-radius: 3px;
    border: 1px solid rgba(255, 255, 255, 0.1);
}

/* 3. 设计滑块的“手柄” (Thumb) - 使用自定义图标 */
input[type="range"]::-webkit-slider-thumb {
    -webkit-appearance: none;
    appearance: none;    
    margin-top: -20px; /* ✨︎图标（手柄）的上下距离，改了大小就要改这里哦，确保滑动的图标在滑动条上 ✨︎ */
    height: 40px; /* 高度 */
    width: 40px; /* 宽度 */

    /* ✨︎图标替换，自改✨︎ */
    background-image: url('https://files.catbox.moe/7kp8d5.png');
    background-size: contain; /* 确保图标完整显示，不被拉伸 */
    background-repeat: no-repeat;
    background-position: center;

    /* 移除所有可能导致“变淡”的默认样式 */
    background-color: transparent; 
    border: none;
    border-radius: 0;
    box-shadow: none;
    transition: transform 0.2s ease; /* 保留悬停放大动画 */
}

/* (可选) 4. 当鼠标悬停或拖动时，让手柄稍微变大 */
input[type="range"]:hover::-webkit-slider-thumb,
input[type="range"]:active::-webkit-slider-thumb {
    transform: scale(1.2);
}

/* 兼容Firefox浏览器 */
input[type="range"]::-moz-range-track {
    height: 6px; /* ✨︎图标（手柄）的上下距离✨︎ */
    background: linear-gradient(to right, #ebebeb, #b6ded7); /* 改色和上边一样 */
    border-radius: 3px;
    border: 1px solid rgba(255, 255, 255, 0.1);
}

input[type="range"]::-moz-range-thumb {
    height: 20px;
    width: 20px; /* 大小自调  */
    background-image: url('https://files.catbox.moe/7kp8d5.png');
    background-size: contain;
    background-repeat: no-repeat;
    background-position: center;
    background-color: transparent;
    border: none;
    border-radius: 0;
}

